subTitle:
, function() {
    fetch('https://api.52vmy.cn/api/wl/yan/yanyu')
        .then(response => response.json())
        .then(data => {
            if (data.code === 200) {
                // Assuming you have an element with id 'subtitle' in your HTML where you want to display the subtitle
                document.getElementById('subtitle').innerText = data.data.content;
            } else {
                console.error('Failed to fetch the saying:', data.msg);
            }
        })
        .catch(error => console.error('Error fetching the saying:', error));
});
